    for (const entry of entries) {
      const full = path.join(current, entry.name);
      if (entry.isDirectory()) {
        stack.push(full);
      } else if (entry.isFile() && entry.name === 'graph-metadata.json') {
        out.push(full);
      }
    }
  }
  return out;
}

